mapper.update:
UPDATE payments
SET status = #{status}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE payments
SET status = 'COMPLETED', paid_at = #{paidAt}, transaction_id = #{transactionId}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

UPDATE payments
SET status = 'FAILED', failure_reason = #{failureReason}, updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}

mapper.select:
SELECT COUNT(*) > 0
FROM payments
WHERE payment_number = #{paymentNumber}

SELECT COUNT(*) > 0
FROM payments
WHERE transaction_id = #{transactionId}

SELECT COUNT(*)
FROM payments
WHERE status = #{status}

SELECT COUNT(*)
FROM payments
WHERE payment_method = #{paymentMethod}
